import{_ as e,o as r,c as a,ag as o}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"Why Piwi? — Comparison & FAQ","description":"","frontmatter":{"title":"Why Piwi? — Comparison & FAQ","lang":"en-US"},"headers":[],"relativePath":"comparison.md","filePath":"comparison.md","lastUpdated":1783697256000}'),i={name:"comparison.md"};function s(d,t,n,l,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="why-piwi" tabindex="-1">Why Piwi? <a class="header-anchor" href="#why-piwi" aria-label="Permalink to &quot;Why Piwi?&quot;">​</a></h1><p>Piwi Dashboard gives your Playwright results a permanent, self-hosted home — with live streaming, failure clustering, flaky-test analytics, and optional AI diagnosis on top. This page explains how it relates to tools you may already use, and answers the questions we hear most.</p><h2 id="the-landscape" tabindex="-1">The landscape <a class="header-anchor" href="#the-landscape" aria-label="Permalink to &quot;The landscape&quot;">​</a></h2><p>Every tool below is good at what it targets. The honest differences:</p><ul><li><strong>Playwright HTML report</strong> — excellent for debugging a single run locally. But it&#39;s per-run and ephemeral: once the next CI build uploads its artifact, yesterday&#39;s context is gone, and there&#39;s no cross-run view (trends, flakiness, clustering) at all. Piwi doesn&#39;t replace it for local work — it replaces the <em>&quot;download the artifact zip from CI&quot;</em> workflow.</li><li><strong>Allure Report</strong> — a mature, multi-framework report generator producing a rich static report. History across builds requires wiring previous results into each build, and there&#39;s no server, live view, or cross-run analytics in the open-source generator (that&#39;s the commercial TestOps product).</li><li><strong>ReportPortal</strong> — a mature, framework-agnostic, self-hosted test-ops platform with ML-based failure triage. It&#39;s built for organizations aggregating many frameworks, and its self-hosted footprint matches that ambition: a multi-service stack (API services, PostgreSQL, RabbitMQ, OpenSearch). Piwi trades that breadth for Playwright-native depth in a single container.</li><li><strong>Currents</strong> — a polished commercial SaaS for Playwright and Cypress: run history, flake detection, CI orchestration. It&#39;s managed and maintained for you; in exchange it&#39;s paid and your test data lives on their infrastructure.</li></ul><h2 id="feature-comparison" tabindex="-1">Feature comparison <a class="header-anchor" href="#feature-comparison" aria-label="Permalink to &quot;Feature comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><strong>Piwi</strong></th><th>Playwright HTML report</th><th>Allure Report</th><th>ReportPortal</th><th>Currents</th></tr></thead><tbody><tr><td>Run history across builds</td><td>✅</td><td>❌ per-run</td><td>➖ manual wiring</td><td>✅</td><td>✅</td></tr><tr><td>Self-hosted</td><td>✅ single container</td><td>—</td><td>➖ static files</td><td>✅ multi-service stack</td><td>❌ SaaS</td></tr><tr><td>Live run streaming</td><td>✅ SSE, per-test</td><td>❌</td><td>❌</td><td>➖</td><td>✅</td></tr><tr><td>Playwright traces, first-class</td><td>✅ stored + viewer links</td><td>✅</td><td>➖ attachments</td><td>➖ attachments</td><td>✅</td></tr><tr><td>Flaky detection &amp; scoring</td><td>✅ composite score, root-cause classes, CI-cost impact</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Failure clustering</td><td>✅ error fingerprinting</td><td>❌</td><td>❌</td><td>✅ ML-based</td><td>✅</td></tr><tr><td>AI failure diagnosis</td><td>✅ optional, grounded in your git diff, patches validated server-side</td><td>❌</td><td>❌</td><td>➖ ML triage</td><td>➖</td></tr><tr><td>Locator healing suggestions</td><td>✅ from prior passing runs</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Web vitals &amp; network capture</td><td>✅</td><td>➖ in traces</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>MCP server for AI agents</td><td>✅ 38 tools</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>Framework support</td><td>Playwright only (by design)</td><td>Playwright</td><td>Many</td><td>Many</td><td>Playwright, Cypress, Jest…</td></tr><tr><td>Price</td><td>Free, MIT</td><td>Free</td><td>Free</td><td>Free (self-host) / paid SaaS</td><td>Paid</td></tr></tbody></table><h2 id="when-piwi-is-not-the-right-choice" tabindex="-1">When Piwi is <em>not</em> the right choice <a class="header-anchor" href="#when-piwi-is-not-the-right-choice" aria-label="Permalink to &quot;When Piwi is *not* the right choice&quot;">​</a></h2><ul><li><strong>You aggregate many test frameworks</strong> (JUnit, pytest, Cypress, …) into one place → ReportPortal or Allure fit better. Piwi is deliberately Playwright-only: that&#39;s what makes traces, locator healing, and step-level analytics first-class.</li><li><strong>You want a managed service with CI orchestration</strong> and someone else on the pager → Currents.</li><li><strong>You only debug locally</strong> and never look back at CI history → the built-in HTML report is already great.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="is-my-data-safe-does-piwi-phone-home" tabindex="-1">Is my data safe? Does Piwi phone home? <a class="header-anchor" href="#is-my-data-safe-does-piwi-phone-home" aria-label="Permalink to &quot;Is my data safe? Does Piwi phone home?&quot;">​</a></h3><p><strong>Zero telemetry.</strong> Piwi makes no outbound calls except the ones you explicitly configure: your AI provider (if you enable diagnosis), your SMTP server, your S3 endpoint, your Slack/webhook URLs, and your git host (if you connect a repository). No analytics, no update pings, no crash reporting. Your test results live in your SQLite file or PostgreSQL database, on your infrastructure.</p><h3 id="does-ai-diagnosis-send-my-code-to-a-third-party" tabindex="-1">Does AI diagnosis send my code to a third party? <a class="header-anchor" href="#does-ai-diagnosis-send-my-code-to-a-third-party" aria-label="Permalink to &quot;Does AI diagnosis send my code to a third party?&quot;">​</a></h3><p>Only if you turn it on, and only to the provider <em>you</em> configure. The diagnosis context (error messages, failing steps, the relevant git diff, screenshots) is sent to your configured endpoint — Anthropic, OpenAI, or any OpenAI-compatible URL, including a fully local model via Ollama/vLLM. You can preview the exact context before it&#39;s sent, and cap its size in Settings. With no provider configured, the feature stays off and nothing leaves your server.</p><h3 id="sqlite-or-postgresql" tabindex="-1">SQLite or PostgreSQL? <a class="header-anchor" href="#sqlite-or-postgresql" aria-label="Permalink to &quot;SQLite or PostgreSQL?&quot;">​</a></h3><p>Start with SQLite — it&#39;s zero-config and easily handles a team&#39;s test volume. Switch to PostgreSQL (<code>PIWI_DATABASE_URL</code>) when you want concurrent write headroom, an existing backup story, or your ops standard is Postgres. Both backends are exercised by the project&#39;s CI on every commit.</p><h3 id="why-does-the-dashboard-require-node-24" tabindex="-1">Why does the dashboard require Node 24? <a class="header-anchor" href="#why-does-the-dashboard-require-node-24" aria-label="Permalink to &quot;Why does the dashboard require Node 24?&quot;">​</a></h3><p>The dashboard server targets current Node (the Docker image ships it, so this only matters when running from source). The <strong>reporter</strong> that runs inside your test project is much less demanding — Node 18+ — so your test suite&#39;s runtime doesn&#39;t need to change.</p><h3 id="can-i-use-it-with-cypress-jest-other-frameworks" tabindex="-1">Can I use it with Cypress / Jest / other frameworks? <a class="header-anchor" href="#can-i-use-it-with-cypress-jest-other-frameworks" aria-label="Permalink to &quot;Can I use it with Cypress / Jest / other frameworks?&quot;">​</a></h3><p>No — Piwi is Playwright-only by design. The ingest API, trace handling, step analytics, and locator healing are all built around Playwright&#39;s model. Breadth is what ReportPortal and Allure are for.</p><h3 id="is-it-production-ready" tabindex="-1">Is it production-ready? <a class="header-anchor" href="#is-it-production-ready" aria-label="Permalink to &quot;Is it production-ready?&quot;">​</a></h3><p>Piwi is a young project under active development (pre-1.0, semver). It&#39;s exercised by a CI matrix across SQLite/PostgreSQL × local/S3 storage with a large Playwright E2E suite, and upgrades run database migrations automatically. Pin a version tag, keep backups of <code>.data/</code> (<a href="/deployment.html">deployment guide</a>), and expect occasional breaking changes between minor versions until 1.0.</p><h3 id="how-much-disk-ram-does-it-need" tabindex="-1">How much disk/RAM does it need? <a class="header-anchor" href="#how-much-disk-ram-does-it-need" aria-label="Permalink to &quot;How much disk/RAM does it need?&quot;">​</a></h3><p>Modest — see <a href="/deployment.html#resource-requirements">resource requirements</a>. Disk is the real variable: traces and HTML reports dominate, and you can prune old runs from Settings → Storage.</p><h3 id="where-do-i-ask-questions-or-propose-features" tabindex="-1">Where do I ask questions or propose features? <a class="header-anchor" href="#where-do-i-ask-questions-or-propose-features" aria-label="Permalink to &quot;Where do I ask questions or propose features?&quot;">​</a></h3><p><a href="https://github.com/PiwiTests/platform/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a> for questions and ideas, <a href="https://github.com/PiwiTests/platform/issues" target="_blank" rel="noreferrer">issues</a> for bugs, and <a href="https://github.com/PiwiTests/platform/blob/main/ROADMAP.md" target="_blank" rel="noreferrer">ROADMAP.md</a> for direction.</p><hr><p><sub>Product names are used for identification only. Piwi Dashboard is an independent project, not affiliated with, endorsed by, or connected to Microsoft Corporation (Playwright), Qameta Software (Allure), EPAM Systems (ReportPortal), or Currents Software. Details about third-party products reflect their publicly documented open-source/free tiers and may change — corrections welcome.</sub></p>',28)])])}const g=e(i,[["render",s]]);export{p as __pageData,g as default};
